diff --git a/llvm/lib/Transforms/InstCombine/InstCombineCompares.cpp b/llvm/lib/Transforms/InstCombine/InstCombineCompares.cpp
index 9df08553d86e..d2f594e88857 100644
--- a/llvm/lib/Transforms/InstCombine/InstCombineCompares.cpp
+++ b/llvm/lib/Transforms/InstCombine/InstCombineCompares.cpp
@@ -8701,6 +8701,10 @@ Instruction *InstCombinerImpl::visitFCmpInst(FCmpInst &I) {
       if (Instruction *NV = foldFCmpIntToFPConst(I, LHSI, RHSC))
         return NV;
       break;
+    case Instruction::FPTrunc:
+      if (Instruction *NV = foldFCmpFPTruncConst(I, LHSI, RHSC))
+        return NV;
+      break;
     case Instruction::FDiv:
       if (Instruction *NV = foldFCmpReciprocalAndZero(I, LHSI, RHSC))
         return NV;
@@ -8789,6 +8793,82 @@ Instruction *InstCombinerImpl::visitFCmpInst(FCmpInst &I) {
       }
     }
   }
+  if (match(Op0, m_FPTrunc(m_Value(X)))) {
+    if (match(Op1, m_FPTrunc(m_Value(Y))) && X->getType() == Y->getType())
+      return new FCmpInst(Pred, X, Y, "", &I);
+
+    const APFloat *C;
+    if (match(Op1, m_APFloat(C))) {
+      // fcmp (fptrunc x), C -> fcmp x, C'
+      const fltSemantics &XSem = X->getType()->getScalarType()->getFltSemantics();
+      bool IsGreater = (Pred == FCmpInst::FCMP_OGE || Pred == FCmpInst::FCMP_UGE ||
+                        Pred == FCmpInst::FCMP_OGT || Pred == FCmpInst::FCMP_UGT);
+      bool IsLess = (Pred == FCmpInst::FCMP_OLE || Pred == FCmpInst::FCMP_ULE ||
+                     Pred == FCmpInst::FCMP_OLT || Pred == FCmpInst::FCMP_ULT);
+
+      if ((IsGreater || IsLess) && !C->isNaN()) {
+        bool NextDown = false;
+        if (Pred == FCmpInst::FCMP_OGE || Pred == FCmpInst::FCMP_UGE ||
+            Pred == FCmpInst::FCMP_OLT || Pred == FCmpInst::FCMP_ULT) {
+            // (fptrunc X) >= C  <=> X >= Mid(C, nextDown(C))
+            // (fptrunc X) < C   <=> X < Mid(C, nextDown(C))
+            NextDown = true;
+        } else {
+            // (fptrunc X) <= C  <=> X <= Mid(C, nextUp(C))
+            // (fptrunc X) > C   <=> X > Mid(C, nextUp(C))
+            NextDown = false;
+        }
+
+        APFloat Bound = *C;
+        Bound.next(NextDown);
+        
+        bool Lossy;
+        APFloat BoundExt = Bound;
+        BoundExt.convert(XSem, APFloat::rmNearestTiesToEven, &Lossy);
+        
+        APFloat CExt = *C;
+        CExt.convert(XSem, APFloat::rmNearestTiesToEven, &Lossy);
+        
+        APFloat Mid = BoundExt;
+        Mid.add(CExt, APFloat::rmNearestTiesToEven);
+        APFloat Two(XSem, "2.0");
+        Mid.divide(Two, APFloat::rmNearestTiesToEven);
+
+        APFloat TruncMid = Mid;
+        TruncMid.convert(C->getSemantics(), APFloat::rmNearestTiesToEven, &Lossy);
+        
+        bool MidRoundsToC = TruncMid.bitwiseIsEqual(*C);
+        bool MidRoundsToBound = TruncMid.bitwiseIsEqual(Bound);
+
+        if (MidRoundsToC || MidRoundsToBound) {
+          if (Pred == FCmpInst::FCMP_OGE || Pred == FCmpInst::FCMP_UGE ||
+              Pred == FCmpInst::FCMP_OLE || Pred == FCmpInst::FCMP_ULE) {
+             // OGE: (fptrunc X) >= C  <=> X >= Mid (if Mid rounds to C)  or X > Mid (if rounds to Bound)
+             // OLE: (fptrunc X) <= C  <=> X <= Mid (if Mid rounds to C)  or X < Mid (if rounds to Bound)
+             CmpInst::Predicate NewPred = Pred;
+             if (!MidRoundsToC) { // Mid rounds to Bound, so Mid itself is not included.
+                 if (Pred == FCmpInst::FCMP_OGE) NewPred = FCmpInst::FCMP_OGT;
+                 else if (Pred == FCmpInst::FCMP_UGE) NewPred = FCmpInst::FCMP_UGT;
+                 else if (Pred == FCmpInst::FCMP_OLE) NewPred = FCmpInst::FCMP_OLT;
+                 else if (Pred == FCmpInst::FCMP_ULE) NewPred = FCmpInst::FCMP_ULT;
+             }
+             return new FCmpInst(NewPred, X, ConstantFP::get(X->getType(), Mid), "", &I);
+          } else {
+             // OLT: (fptrunc X) < C   <=> X < Mid (if Mid rounds to C)  or X <= Mid (if rounds to Bound)
+             // OGT: (fptrunc X) > C   <=> X > Mid (if Mid rounds to C)  or X >= Mid (if rounds to Bound)
+             CmpInst::Predicate NewPred = Pred;
+             if (!MidRoundsToC) { // Mid rounds to Bound, so Mid itself IS included.
+                 if (Pred == FCmpInst::FCMP_OLT) NewPred = FCmpInst::FCMP_OLE;
+                 else if (Pred == FCmpInst::FCMP_ULT) NewPred = FCmpInst::FCMP_ULE;
+                 else if (Pred == FCmpInst::FCMP_OGT) NewPred = FCmpInst::FCMP_OGE;
+                 else if (Pred == FCmpInst::FCMP_UGT) NewPred = FCmpInst::FCMP_UGE;
+             }
+             return new FCmpInst(NewPred, X, ConstantFP::get(X->getType(), Mid), "", &I);
+          }
+        }
+      }
+    }
+  }

   // Convert a sign-bit test of an FP value into a cast and integer compare.
   // TODO: Simplify if the copysign constant is 0.0 or NaN.
