{"command":"cat <<'CODEEOF' | python $AGENT_TOOLS_DIR/apply_code.py write llvm/lib/Transforms/InstCombine/InstCombineCompares.cpp 8792 8810
  if (match(Op0, m_FPTrunc(m_Value(X)))) {
    if (match(Op1, m_FPTrunc(m_Value(Y))) && X->getType() == Y->getType())
      return new FCmpInst(Pred, X, Y, "", &I);

    const APFloat *C;
    if (match(Op1, m_APFloat(C))) {
      // fcmp (fptrunc x), C
      // A float constant C has a range of double values that round to it.
      // Let [C_min, C_max] be the range of values that round to C.
      // If predicate is OGE / UGE:
      // (fptrunc X) >= C  <=>  X >= C_min
      // If predicate is OLT / ULT:
      // (fptrunc X) < C   <=>  X < C_min
      // If predicate is OGT / UGT:
      // (fptrunc X) > C   <=>  X > C_max
      // If predicate is OLE / ULE:
      // (fptrunc X) <= C  <=>  X <= C_max

      const fltSemantics &XSem = X->getType()->getScalarType()->getFltSemantics();

      bool IsStrict = (Pred == FCmpInst::FCMP_OLT || Pred == FCmpInst::FCMP_ULT ||
                       Pred == FCmpInst::FCMP_OGT || Pred == FCmpInst::FCMP_UGT);
      bool IsGreater = (Pred == FCmpInst::FCMP_OGE || Pred == FCmpInst::FCMP_UGE ||
                        Pred == FCmpInst::FCMP_OGT || Pred == FCmpInst::FCMP_UGT);

      // C_min is the midpoint between C and the next smaller float.
      // C_max is the midpoint between C and the next larger float.
      if (!C->isNaN() && !C->isZero()) { // Just handle non-zero/NaN for simplicity initially
        // Actually, zero is tricky because -0.0 and +0.0, but maybe we can just use nextafter.
      }
    }
  }

