{"command":"cat <<'CODEEOF' | python $AGENT_TOOLS_DIR/apply_code.py write llvm/lib/Transforms/InstCombine/InstCombineCompares.cpp 8792 8824
  if (match(Op0, m_FPTrunc(m_Value(X)))) {
    if (match(Op1, m_FPTrunc(m_Value(Y))) && X->getType() == Y->getType())
      return new FCmpInst(Pred, X, Y, "", &I);

    const APFloat *C;
    if (match(Op1, m_APFloat(C))) {
      // fcmp (fptrunc x), C
      // We can convert this to a comparison in the wider type.
      // (fptrunc X) >= C  <=>  X >= C_min
      // (fptrunc X) <= C  <=>  X <= C_max
      // (fptrunc X) > C   <=>  X > C_max
      // (fptrunc X) < C   <=>  X < C_min

      const fltSemantics &XSem = X->getType()->getScalarType()->getFltSemantics();

      bool IsStrict = (Pred == FCmpInst::FCMP_OLT || Pred == FCmpInst::FCMP_ULT ||
                       Pred == FCmpInst::FCMP_OGT || Pred == FCmpInst::FCMP_UGT);
      bool IsGreater = (Pred == FCmpInst::FCMP_OGE || Pred == FCmpInst::FCMP_UGE ||
                        Pred == FCmpInst::FCMP_OGT || Pred == FCmpInst::FCMP_UGT);
      bool IsLess = (Pred == FCmpInst::FCMP_OLE || Pred == FCmpInst::FCMP_ULE ||
                     Pred == FCmpInst::FCMP_OLT || Pred == FCmpInst::FCMP_ULT);

      if ((IsGreater || IsLess) && !C->isNaN()) {
        APFloat Bound = *C;
        Bound.next(IsGreater ? true : false); // if greater, we want C_min, so nextDown (true). Wait, nextDown(true) means next smaller.

        bool Lossy;
        APFloat BoundExt = Bound;
        BoundExt.convert(XSem, APFloat::rmNearestTiesToEven, &Lossy);

        APFloat CExt = *C;
        CExt.convert(XSem, APFloat::rmNearestTiesToEven, &Lossy);

        APFloat Mid = BoundExt;
        Mid.add(CExt, APFloat::rmNearestTiesToEven);
        // Divide by 2:
        APFloat Two(XSem, "2.0");
        Mid.divide(Two, APFloat::rmNearestTiesToEven);

        // Wait, what if ties-to-even behavior means that midpoint itself truncates to C or Bound?
        // Let's verify midpoint. Midpoint between C and nextDown(C) rounds to even.
        // If the lower bit of C is 0, mid rounds to C. If 1, mid rounds to nextDown(C).
        // Let's defer exact boundary matching and use Alive2.
      }
    }
  }

